import{_ as n,C as t,o,c as r,a2 as a,E as i}from"./chunks/framework.BKG_UbFK.js";const k=JSON.parse('{"title":"Permissions","description":"","frontmatter":{},"headers":[],"relativePath":"en/features/permissions.md","filePath":"en/features/permissions.md"}'),l={name:"en/features/permissions.md"};function c(p,e,d,h,m,g){const s=t("Screenshot");return o(),r("div",null,[e[0]||(e[0]=a('<h1 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h1><p>The Permissions panel is a full CRUD interface over Spatie&#39;s <code>Permission</code> model. Clearance never introduces its own permission table - every permission you create here is a regular Spatie permission, usable anywhere Spatie&#39;s API is used (<code>$user-&gt;can()</code>, <code>Gate::allows()</code>, policies, <code>@can</code>).</p><h2 id="what-the-panel-does" tabindex="-1">What the panel does <a class="header-anchor" href="#what-the-panel-does" aria-label="Permalink to &quot;What the panel does&quot;">​</a></h2><ul><li><strong>Create</strong> - add a new permission, validated against the <a href="#permission-naming-convention">naming convention</a> (unless disabled) and scoped to a guard.</li><li><strong>Edit</strong> - rename a permission or change its guard.</li><li><strong>Delete</strong> - remove a permission and its role/user assignments (standard Spatie cascade behavior).</li></ul>',4)),i(s,{src:"/screenshots/permissions-page.png",alt:"Clearance Permissions panel listing permissions grouped by naming prefix",caption:"The Permissions panel lists every Spatie permission, grouped by naming prefix."}),i(s,{src:"/screenshots/permission-form-modal.png",alt:"Permission create/edit form with naming convention validation",caption:"The permission form validates the group-action naming convention before saving."}),e[1]||(e[1]=a(`<h2 id="permission-naming-convention" tabindex="-1">Permission Naming Convention <a class="header-anchor" href="#permission-naming-convention" aria-label="Permalink to &quot;Permission Naming Convention&quot;">​</a></h2><p>Permissions must follow the <code>group-action</code> format:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders-create       correct</span></span>
<span class="line"><span>orders-read         correct</span></span>
<span class="line"><span>store-orders-delete correct</span></span>
<span class="line"><span></span></span>
<span class="line"><span>create              wrong (bare action, no group)</span></span>
<span class="line"><span>orders.create       wrong (dot separator)</span></span>
<span class="line"><span>Orders-Create       wrong (camelCase)</span></span></code></pre></div><p>The group prefix (<code>orders</code> in <code>orders-create</code>) is what the <a href="/clearance-docs/en/features/dashboard.html">Dashboard</a> uses to count distinct permission groups.</p><div class="tip custom-block"><p class="custom-block-title">Disabling enforcement</p><p>Some teams migrate from a different naming scheme. Disable the check per environment:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;enforce_naming_convention&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div></div><h2 id="access-control" tabindex="-1">Access control <a class="header-anchor" href="#access-control" aria-label="Permalink to &quot;Access control&quot;">​</a></h2><p>Read access to the panel (viewing the permission list) requires <code>clearance-access</code>. Creating, editing, or deleting a permission additionally requires <code>clearance-permissions-write</code>:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-permissions-write&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title"><code>clearance-*</code> permissions are reserved</p><p>The <code>clearance-*</code> permissions themselves (<code>clearance-access</code>, <code>clearance-permissions-write</code>, etc.) cannot be created, renamed, or deleted through this panel - even by a <code>super_admin</code> actor. They&#39;re managed exclusively by the package&#39;s own install flow. See <a href="/clearance-docs/en/features/super-admin.html#reserved-clearance-permissions">Super Admin</a>.</p></div><h2 id="route-and-embedded-component" tabindex="-1">Route and embedded component <a class="header-anchor" href="#route-and-embedded-component" aria-label="Permalink to &quot;Route and embedded component&quot;">​</a></h2><table tabindex="0"><thead><tr><th>URI</th><th>Route name</th><th>Description</th></tr></thead><tbody><tr><td><code>/clearance/permissions</code></td><td><code>clearance.permissions</code></td><td>Permission CRUD with group-prefix naming validation</td></tr></tbody></table><div class="language-blade vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">blade</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">livewire:clearance::permissions.permission-manager</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre></div><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/clearance-docs/en/features/roles.html">Roles</a> - assign permissions to a role, guard-scoped.</li><li><a href="/clearance-docs/en/features/super-admin.html">Super Admin</a> - the full fine-grained write-permission table.</li><li><a href="/clearance-docs/en/guide/configuration.html">Configuration reference</a> - <code>enforce_naming_convention</code>, <code>naming_separator</code>.</li></ul>`,14))])}const b=n(l,[["render",c]]);export{k as __pageData,b as default};
